const item = $input.first();
const body = item.json.body ?? item.json;
const binaryEntry = item.binary ? Object.values(item.binary)[0] : null;
const normalizeSourceType = (value) => {
  const raw = String(value || '').toLowerCase().trim();
  const map = {
    'sell-in': 'sell_in',
    'sellin': 'sell_in',
    'sell_in': 'sell_in',
    'sell-out': 'sell_out',
    'sellout': 'sell_out',
    'sell_out': 'sell_out',
    'payment': 'payment',
    'payments': 'payment',
    'inventory': 'inventory'
  };
  return map[raw] || raw;
};
const sourceType = normalizeSourceType(body.sourceType || body.source_type || process.env.DEFAULT_SOURCE_TYPE || '');
const sourceParty = String(body.sourceParty || body.source_party || process.env.DEFAULT_SOURCE_PARTY || 'manual_admin').toLowerCase().trim();
const channel = String(body.channel || process.env.DEFAULT_CHANNEL || 'all').toLowerCase().trim();
const now = new Date();
const periodMonth = Number(body.periodMonth || body.period_month || process.env.DEFAULT_PERIOD_MONTH || (now.getMonth() + 1));
const periodYear = Number(body.periodYear || body.period_year || process.env.DEFAULT_PERIOD_YEAR || now.getFullYear());
const inlineRecords = Array.isArray(body.records) ? body.records : null;
const fileName = binaryEntry?.fileName || body.fileName || `${sourceType || 'batch'}-${periodYear}-${String(periodMonth).padStart(2, '0')}.csv`;
const fileExtension = String(binaryEntry?.fileExtension || fileName.split('.').pop() || 'csv').toLowerCase();
const fileSizeBytes = Number(binaryEntry?.fileSize || body.fileSizeBytes || (inlineRecords ? JSON.stringify(inlineRecords).length : 0));
const fileChecksum = String(body.fileChecksum || body.file_checksum || `${sourceType}|${sourceParty}|${channel}|${periodYear}|${periodMonth}|${fileName}|${fileSizeBytes}`);
return [{
  json: {
    triggerMode: 'webhook',
    sourceType,
    sourceParty,
    channel,
    periodMonth,
    periodYear,
    fileName,
    fileExtension,
    mimeType: binaryEntry?.mimeType || body.mimeType || 'application/octet-stream',
    fileSizeBytes,
    fileChecksum,
    uploadedBy: body.uploadedBy || body.uploaded_by || 'n8n-webhook',
    receivedAt: body.receivedAt || body.received_at || now.toISOString(),
    inlineRecords
  },
  binary: binaryEntry ? { data: binaryEntry } : undefined
}];

const input = $input.first();
const j = input.json;
const allowedSourceTypes = ['sell_in', 'sell_out', 'inventory', 'payment'];
const allowedSourceParties = ['koprindo', 'gunawan_elektro', 'ritel_modern', 'konsultan', 'manual_admin'];
const allowedChannels = ['alfamart', 'indomaret', 'aksesmu', 'all'];
const createUuid = () => {
  if (globalThis.crypto?.randomUUID) return globalThis.crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};
if (!allowedSourceTypes.includes(j.sourceType)) {
  throw new Error(`sourceType wajib salah satu dari: ${allowedSourceTypes.join(', ')}`);
}
const hasInlineRecords = Array.isArray(j.inlineRecords) && j.inlineRecords.length > 0;
const hasBinary = !!input.binary?.data?.data;
if (!hasInlineRecords && !hasBinary) {
  throw new Error('Payload harus berisi records JSON atau file binary CSV/XLSX.');
}
const periodMonth = Number(j.periodMonth);
const periodYear = Number(j.periodYear);
if (!Number.isInteger(periodMonth) || periodMonth < 1 || periodMonth > 12) throw new Error('periodMonth tidak valid');
if (!Number.isInteger(periodYear) || periodYear < 2020) throw new Error('periodYear tidak valid');
return [{
  json: {
    ...j,
    batchId: j.batchId || createUuid(),
    sourceParty: allowedSourceParties.includes(j.sourceParty) ? j.sourceParty : 'manual_admin',
    channel: allowedChannels.includes(j.channel) ? j.channel : 'all',
    periodKey: `${periodYear}-${String(periodMonth).padStart(2, '0')}`,
    stockoutThreshold: Number(process.env.KOPRINDO_STOCKOUT_THRESHOLD || 120),
    overstockThreshold: Number(process.env.KOPRINDO_OVERSTOCK_THRESHOLD || 2800),
    reconciliationWarning: Number(process.env.KOPRINDO_RECON_WARNING_THRESHOLD || 0.10),
    reconciliationHigh: Number(process.env.KOPRINDO_RECON_HIGH_THRESHOLD || 0.20),
    reconciliationCritical: Number(process.env.KOPRINDO_RECON_CRITICAL_THRESHOLD || 0.35),
    paymentHighDays: Number(process.env.KOPRINDO_PAYMENT_HIGH_DAYS || 10),
    paymentCriticalDays: Number(process.env.KOPRINDO_PAYMENT_CRITICAL_DAYS || 30)
  },
  binary: input.binary
}];

const envelope = $('Normalize Envelope').first().json;
const rows = $input.all().map((item) => item.json);
if (!rows.length) throw new Error('Tidak ada baris data yang berhasil dibaca.');
const normalizeRow = (row) => Object.fromEntries(Object.entries(row).map(([key, value]) => [String(key).trim().toLowerCase().replace(/[^a-z0-9]+/g, '_'), value]));
const pick = (row, keys, fallback = null) => {
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && row[key] !== '') return row[key];
  }
  return fallback;
};
const toText = (value, fallback = '') => value === undefined || value === null ? fallback : String(value).trim();
const toNumber = (value, fallback = 0) => {
  if (value === undefined || value === null || value === '') return fallback;
  const normalized = String(value).replace(/,/g, '').replace(/\s+/g, '');
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : fallback;
};
const toDate = (value) => {
  if (value === undefined || value === null || value === '') return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString().slice(0, 10);
};
const dayDiff = (dateString) => {
  if (!dateString) return 0;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const target = new Date(dateString);
  target.setHours(0, 0, 0, 0);
  return Math.max(0, Math.floor((today - target) / 86400000));
};
const agingBucket = (days) => {
  if (days <= 30) return '0_30';
  if (days <= 45) return '31_45';
  if (days <= 60) return '46_60';
  return '61_plus';
};
const normalizeParty = (value, fallback) => {
  const allowed = ['koprindo', 'gunawan_elektro', 'ritel_modern', 'konsultan', 'manual_admin'];
  const candidate = toText(value, fallback).toLowerCase();
  return allowed.includes(candidate) ? candidate : fallback;
};
const records = rows.map((rawRow, index) => {
  const row = normalizeRow(rawRow);
  if (envelope.sourceType === 'sell_in') {
    return {
      periodKey: envelope.periodKey,
      channel: toText(pick(row, ['channel']), envelope.channel).toLowerCase(),
      regionCode: toText(pick(row, ['region_code', 'region', 'wilayah']), 'UNKNOWN_REGION'),
      branchCode: toText(pick(row, ['branch_code', 'branch', 'cabang']), 'UNKNOWN_BRANCH'),
      outletCode: toText(pick(row, ['outlet_code', 'outlet', 'outlet_id']), 'UNKNOWN_OUTLET'),
      skuCode: toText(pick(row, ['sku_code', 'sku', 'sku_id']), `ROW_${index + 1}`),
      qtySellIn: toNumber(pick(row, ['qty_sell_in', 'sell_in_qty', 'qty']), 0),
      shipmentDate: toDate(pick(row, ['shipment_date', 'delivery_date', 'tgl_kirim'])),
      receiptDate: toDate(pick(row, ['receipt_date', 'received_date', 'tgl_terima'])),
      rawRowRef: toText(pick(row, ['raw_row_ref']), `row_${index + 1}`)
    };
  }
  if (envelope.sourceType === 'sell_out') {
    return {
      periodKey: envelope.periodKey,
      channel: toText(pick(row, ['channel']), envelope.channel).toLowerCase(),
      regionCode: toText(pick(row, ['region_code', 'region', 'wilayah']), 'UNKNOWN_REGION'),
      branchCode: toText(pick(row, ['branch_code', 'branch', 'cabang']), 'UNKNOWN_BRANCH'),
      outletCode: toText(pick(row, ['outlet_code', 'outlet', 'outlet_id']), 'UNKNOWN_OUTLET'),
      skuCode: toText(pick(row, ['sku_code', 'sku', 'sku_id']), `ROW_${index + 1}`),
      qtySellOut: toNumber(pick(row, ['qty_sell_out', 'sell_out_qty', 'qty']), 0),
      salesAmount: toNumber(pick(row, ['sales_amount', 'amount', 'nilai_penjualan']), 0),
      transactionCount: toNumber(pick(row, ['transaction_count', 'trx_count', 'jumlah_transaksi']), 0),
      rawRowRef: toText(pick(row, ['raw_row_ref']), `row_${index + 1}`)
    };
  }
  if (envelope.sourceType === 'inventory') {
    return {
      periodKey: envelope.periodKey,
      channel: toText(pick(row, ['channel']), envelope.channel).toLowerCase(),
      regionCode: toText(pick(row, ['region_code', 'region', 'wilayah']), 'UNKNOWN_REGION'),
      branchCode: toText(pick(row, ['branch_code', 'branch', 'cabang']), 'UNKNOWN_BRANCH'),
      outletCode: toText(pick(row, ['outlet_code', 'outlet', 'outlet_id']), 'UNKNOWN_OUTLET'),
      skuCode: toText(pick(row, ['sku_code', 'sku', 'sku_id']), `ROW_${index + 1}`),
      openingStock: toNumber(pick(row, ['opening_stock', 'stock_awal']), 0),
      closingStock: toNumber(pick(row, ['closing_stock', 'stock_akhir', 'stock']), 0),
      stockSnapshotDate: toDate(pick(row, ['stock_snapshot_date', 'snapshot_date', 'tgl_stok'])) || new Date().toISOString().slice(0, 10)
    };
  }
  const invoiceDate = toDate(pick(row, ['invoice_date', 'tanggal_invoice'])) || new Date().toISOString().slice(0, 10);
  const dueDate = toDate(pick(row, ['due_date', 'jatuh_tempo'])) || invoiceDate;
  const paidAmount = toNumber(pick(row, ['paid_amount', 'jumlah_bayar']), 0);
  const invoiceAmount = toNumber(pick(row, ['invoice_amount', 'amount', 'nilai_invoice']), 0);
  const outstanding = Math.max(0, invoiceAmount - paidAmount);
  let paymentStatus = 'unpaid';
  if (outstanding <= 0) paymentStatus = 'paid';
  else if (paidAmount > 0) paymentStatus = 'partial';
  if (outstanding > 0 && dayDiff(dueDate) > 0) paymentStatus = 'overdue';
  const agingDays = dayDiff(dueDate);
  return {
    periodKey: envelope.periodKey,
    invoiceId: toText(pick(row, ['invoice_id', 'invoice_number', 'nomor_invoice']), `INV-${index + 1}`),
    invoiceType: toText(pick(row, ['invoice_type', 'tipe_invoice']), 'retail_to_koprindo'),
    payerParty: normalizeParty(pick(row, ['payer_party', 'payer']), envelope.sourceParty),
    payeeParty: normalizeParty(pick(row, ['payee_party', 'payee']), 'koprindo'),
    invoiceDate,
    invoiceReceivedDate: toDate(pick(row, ['invoice_received_date', 'received_date'])),
    dueDate,
    invoiceAmount,
    paidAmount,
    lastPaymentDate: toDate(pick(row, ['last_payment_date', 'payment_date'])),
    paymentStatus,
    agingDays,
    agingBucket: agingBucket(agingDays)
  };
});
return [{
  json: {
    ...envelope,
    records,
    recordCount: records.length
  }
}];

const payload = $input.first().json;
const records = payload.records || [];
if (!records.length) throw new Error('Batch tidak memiliki records.');
let blockingIssueCount = 0;
let warningIssueCount = 0;
const issues = [];
for (const record of records) {
  if (payload.sourceType === 'payment') {
    if (!record.invoiceId || !record.invoiceDate || !record.dueDate || record.invoiceAmount <= 0) {
      blockingIssueCount += 1;
      issues.push('Ada record payment tanpa invoiceId, invoiceDate, dueDate, atau invoiceAmount valid.');
    }
    if (record.paidAmount > record.invoiceAmount) {
      warningIssueCount += 1;
      issues.push('Ada record payment dengan paidAmount lebih besar dari invoiceAmount.');
    }
    continue;
  }
  if (!record.regionCode || !record.branchCode || !record.outletCode || !record.skuCode) {
    blockingIssueCount += 1;
    issues.push('Ada record operasional tanpa regionCode, branchCode, outletCode, atau skuCode lengkap.');
  }
  if (payload.sourceType === 'sell_in' && Number(record.qtySellIn) <= 0) {
    warningIssueCount += 1;
    issues.push('Ada record sell_in dengan qty <= 0.');
  }
  if (payload.sourceType === 'sell_out' && Number(record.qtySellOut) <= 0) {
    warningIssueCount += 1;
    issues.push('Ada record sell_out dengan qty <= 0.');
  }
  if (payload.sourceType === 'inventory' && Number(record.closingStock) < 0) {
    warningIssueCount += 1;
    issues.push('Ada record inventory dengan closingStock negatif.');
  }
}
const uniqueIssues = [...new Set(issues)];
const qualityScore = Math.max(0, 100 - (blockingIssueCount * 15) - (warningIssueCount * 3));
const qualityStatus = blockingIssueCount > 0 ? 'blocked' : (warningIssueCount > 0 || qualityScore < 90 ? 'provisional' : 'passed');
const registryValidationStatus = qualityStatus === 'blocked' ? 'rejected' : 'published';
const duplicateCheckQuery = `SELECT COUNT(*)::int AS duplicate_count, COALESCE(MAX(batch_id)::text, '') AS existing_batch_id FROM batch_registry WHERE source_type='${payload.sourceType}' AND file_checksum='${String(payload.fileChecksum).replace(/'/g, "''")}' AND period_month=${Number(payload.periodMonth)} AND period_year=${Number(payload.periodYear)};`;
return [{
  json: {
    ...payload,
    qualityScore: Number(qualityScore.toFixed(2)),
    blockingIssueCount,
    warningIssueCount,
    qualityStatus,
    registryValidationStatus,
    reviewRequired: qualityStatus !== 'passed',
    qualityNotes: uniqueIssues,
    duplicateCheckQuery
  }
}];

const payload = $('Validate And Score').first().json;
const esc = (value) => String(value ?? '').replace(/'/g, "''");
const sqlText = (value) => value === undefined || value === null || value === '' ? 'NULL' : `'${esc(value)}'`;
const sqlNum = (value) => Number.isFinite(Number(value)) ? String(Number(value)) : '0';
const sqlDate = (value) => value ? `'${esc(value)}'` : 'NULL';
const queries = [];
queries.push('BEGIN;');
queries.push(`INSERT INTO batch_registry (batch_id, source_type, source_party, channel, period_month, period_year, file_name, file_checksum, file_size_bytes, received_at, validation_status, quality_score) VALUES ('${esc(payload.batchId)}', '${esc(payload.sourceType)}', '${esc(payload.sourceParty)}', ${sqlText(payload.channel)}, ${sqlNum(payload.periodMonth)}, ${sqlNum(payload.periodYear)}, '${esc(payload.fileName)}', '${esc(payload.fileChecksum)}', ${sqlNum(payload.fileSizeBytes)}, '${esc(payload.receivedAt)}', '${esc(payload.registryValidationStatus)}', ${sqlNum(payload.qualityScore)});`);
queries.push(`INSERT INTO data_quality_result (batch_id, quality_score, blocking_issue_count, warning_issue_count, review_required, quality_status, quality_notes) VALUES ('${esc(payload.batchId)}', ${sqlNum(payload.qualityScore)}, ${sqlNum(payload.blockingIssueCount)}, ${sqlNum(payload.warningIssueCount)}, ${payload.reviewRequired ? 'true' : 'false'}, '${esc(payload.qualityStatus)}', ${sqlText((payload.qualityNotes || []).join(' | '))});`);
if (payload.qualityStatus !== 'blocked') {
  if (payload.sourceType === 'sell_in') {
    const values = payload.records.map((record) => `('${esc(payload.batchId)}', '${esc(record.periodKey)}', ${sqlText(record.channel)}, '${esc(record.regionCode)}', '${esc(record.branchCode)}', '${esc(record.outletCode)}', '${esc(record.skuCode)}', ${sqlNum(record.qtySellIn)}, ${sqlDate(record.shipmentDate)}, ${sqlDate(record.receiptDate)}, '${esc(record.rawRowRef)}')`).join(',\n');
    queries.push(`INSERT INTO sell_in_record (batch_id, period_key, channel, region_code, branch_code, outlet_code, sku_code, qty_sell_in, shipment_date, receipt_date, raw_row_ref) VALUES ${values};`);
  }
  if (payload.sourceType === 'sell_out') {
    const values = payload.records.map((record) => `('${esc(payload.batchId)}', '${esc(record.periodKey)}', '${esc(record.channel)}', '${esc(record.regionCode)}', '${esc(record.branchCode)}', '${esc(record.outletCode)}', '${esc(record.skuCode)}', ${sqlNum(record.qtySellOut)}, ${sqlNum(record.salesAmount)}, ${sqlNum(record.transactionCount)}, '${esc(record.rawRowRef)}')`).join(',\n');
    queries.push(`INSERT INTO sell_out_record (batch_id, period_key, channel, region_code, branch_code, outlet_code, sku_code, qty_sell_out, sales_amount, transaction_count, raw_row_ref) VALUES ${values};`);
  }
  if (payload.sourceType === 'inventory') {
    const values = payload.records.map((record) => `('${esc(payload.batchId)}', '${esc(record.periodKey)}', '${esc(record.channel)}', '${esc(record.regionCode)}', '${esc(record.branchCode)}', '${esc(record.outletCode)}', '${esc(record.skuCode)}', ${sqlNum(record.openingStock)}, ${sqlNum(record.closingStock)}, ${sqlDate(record.stockSnapshotDate)})`).join(',\n');
    queries.push(`INSERT INTO inventory_position (batch_id, period_key, channel, region_code, branch_code, outlet_code, sku_code, opening_stock, closing_stock, stock_snapshot_date) VALUES ${values};`);
  }
  if (payload.sourceType === 'payment') {
    const values = payload.records.map((record) => `('${esc(payload.batchId)}', '${esc(record.invoiceId)}', '${esc(record.invoiceType)}', '${esc(record.payerParty)}', '${esc(record.payeeParty)}', ${sqlDate(record.invoiceDate)}, ${sqlDate(record.invoiceReceivedDate)}, ${sqlDate(record.dueDate)}, ${sqlNum(record.invoiceAmount)}, ${sqlNum(record.paidAmount)}, ${sqlDate(record.lastPaymentDate)}, '${esc(record.paymentStatus)}', ${sqlNum(record.agingDays)}, '${esc(record.agingBucket)}')`).join(',\n');
    queries.push(`INSERT INTO payment_record (batch_id, invoice_id, invoice_type, payer_party, payee_party, invoice_date, invoice_received_date, due_date, invoice_amount, paid_amount, last_payment_date, payment_status, aging_days, aging_bucket) VALUES ${values};`);
  }
}
queries.push('COMMIT;');
return [{ json: { ...payload, dbInsertQuery: queries.join('\n') } }];

const payload = $('Validate And Score').first().json;
const events = [];
for (const record of payload.records || []) {
  const entityKey = `${record.channel}:${record.branchCode}:${record.outletCode}:${record.skuCode}`;
  const closingStock = Number(record.closingStock || 0);
  if (closingStock <= Number(payload.stockoutThreshold || 0)) {
    events.push({
      periodKey: payload.periodKey,
      riskType: 'stockout_risk',
      severity: closingStock <= 0 ? 'critical' : 'high',
      entityType: 'outlet',
      entityKey,
      metricName: 'closing_stock',
      observedValue: closingStock,
      thresholdValue: Number(payload.stockoutThreshold || 0),
      status: 'open',
      ownerRole: closingStock <= 0 ? 'management' : 'bd'
    });
    continue;
  }
  if (closingStock >= Number(payload.overstockThreshold || 5000)) {
    events.push({
      periodKey: payload.periodKey,
      riskType: 'overstock_risk',
      severity: closingStock >= Number(payload.overstockThreshold || 5000) * 1.5 ? 'critical' : 'high',
      entityType: 'outlet',
      entityKey,
      metricName: 'closing_stock',
      observedValue: closingStock,
      thresholdValue: Number(payload.overstockThreshold || 5000),
      status: 'open',
      ownerRole: closingStock >= Number(payload.overstockThreshold || 5000) * 1.5 ? 'management' : 'bd'
    });
  }
}
return events.map((json) => ({ json }));

const payload = $('Validate And Score').first().json;
const highDays = Number(payload.paymentHighDays || 7);
const criticalDays = Number(payload.paymentCriticalDays || 30);
const events = [];
for (const record of payload.records || []) {
  const outstanding = Math.max(0, Number(record.invoiceAmount || 0) - Number(record.paidAmount || 0));
  if (outstanding <= 0 || Number(record.agingDays || 0) <= 0) continue;
  let severity = 'warning';
  let thresholdValue = 1;
  let riskType = 'payment_overdue';
  if (Number(record.agingDays || 0) > criticalDays) {
    severity = 'critical';
    thresholdValue = criticalDays;
    riskType = 'payment_aging_critical';
  } else if (Number(record.agingDays || 0) > highDays) {
    severity = 'high';
    thresholdValue = highDays;
  }
  events.push({
    periodKey: payload.periodKey,
    riskType,
    severity,
    entityType: 'invoice',
    entityKey: record.invoiceId,
    metricName: 'overdue_days',
    observedValue: Number(record.agingDays || 0),
    thresholdValue,
    status: 'open',
    ownerRole: 'finance'
  });
}
return events.map((json) => ({ json }));

const payload = $('Validate And Score').first().json;
const warningThreshold = Number(payload.reconciliationWarning || 0.15);
const highThreshold = Number(payload.reconciliationHigh || 0.30);
const criticalThreshold = Number(payload.reconciliationCritical || 0.50);
const events = [];
for (const item of $input.all()) {
  const totalIn = Number(item.json.total_in || 0);
  const totalOut = Number(item.json.total_out || 0);
  if (totalIn <= 0) continue;
  const variance = Number(((totalIn - totalOut) / totalIn).toFixed(4));
  if (variance < warningThreshold) continue;
  let severity = 'warning';
  let thresholdValue = warningThreshold;
  let ownerRole = 'bd';
  if (variance >= criticalThreshold) {
    severity = 'critical';
    thresholdValue = criticalThreshold;
    ownerRole = 'management';
  } else if (variance >= highThreshold) {
    severity = 'high';
    thresholdValue = highThreshold;
    ownerRole = 'bd';
  }
  events.push({
    periodKey: item.json.period_key,
    riskType: 'sell_in_sell_out_mismatch',
    severity,
    entityType: 'outlet',
    entityKey: `${item.json.channel}:${item.json.branch_code}:${item.json.outlet_code}:${item.json.sku_code}`,
    metricName: 'variance_sell_in_sell_out_pct',
    observedValue: variance,
    thresholdValue,
    status: 'open',
    ownerRole
  });
}
return events.map((json) => ({ json }));

const highDays = Number(process.env.KOPRINDO_PAYMENT_HIGH_DAYS || 10);
const criticalDays = Number(process.env.KOPRINDO_PAYMENT_CRITICAL_DAYS || 30);
const events = [];
for (const item of $input.all()) {
  const overdueDays = Number(item.json.aging_days || 0);
  if (overdueDays <= 0) continue;
  let severity = 'warning';
  let thresholdValue = 1;
  let riskType = 'payment_overdue';
  if (overdueDays > criticalDays) {
    severity = 'critical';
    thresholdValue = criticalDays;
    riskType = 'payment_aging_critical';
  } else if (overdueDays > highDays) {
    severity = 'high';
    thresholdValue = highDays;
  }
  events.push({
    periodKey: item.json.period_key,
    riskType,
    severity,
    entityType: 'invoice',
    entityKey: item.json.invoice_id,
    metricName: 'overdue_days',
    observedValue: overdueDays,
    thresholdValue,
    status: 'open',
    ownerRole: 'finance'
  });
}
return events.map((json) => ({ json }));

const warningThreshold = Number(process.env.KOPRINDO_RECON_WARNING_THRESHOLD || 0.10);
const highThreshold = Number(process.env.KOPRINDO_RECON_HIGH_THRESHOLD || 0.20);
const criticalThreshold = Number(process.env.KOPRINDO_RECON_CRITICAL_THRESHOLD || 0.35);
const events = [];
for (const item of $input.all()) {
  const totalIn = Number(item.json.total_in || 0);
  const totalOut = Number(item.json.total_out || 0);
  if (totalIn <= 0) continue;
  const variance = Number(((totalIn - totalOut) / totalIn).toFixed(4));
  if (variance < warningThreshold) continue;
  let severity = 'warning';
  let thresholdValue = warningThreshold;
  let ownerRole = 'bd';
  if (variance >= criticalThreshold) {
    severity = 'critical';
    thresholdValue = criticalThreshold;
    ownerRole = 'management';
  } else if (variance >= highThreshold) {
    severity = 'high';
    thresholdValue = highThreshold;
  }
  events.push({
    periodKey: item.json.period_key,
    riskType: 'sell_in_sell_out_mismatch',
    severity,
    entityType: 'outlet',
    entityKey: `${item.json.channel}:${item.json.branch_code}:${item.json.outlet_code}:${item.json.sku_code}`,
    metricName: 'variance_sell_in_sell_out_pct',
    observedValue: variance,
    thresholdValue,
    status: 'open',
    ownerRole
  });
}
return events.map((json) => ({ json }));

const event = $json;
const esc = (value) => String(value ?? '').replace(/'/g, "''");
const observedValue = Number.isFinite(Number(event.observedValue)) ? Number(event.observedValue) : null;
const thresholdValue = Number.isFinite(Number(event.thresholdValue)) ? Number(event.thresholdValue) : null;
const query = `INSERT INTO risk_event (period_key, risk_type, severity, entity_type, entity_key, metric_name, observed_value, "thresholdValue", status, owner_role)
SELECT '${esc(event.periodKey)}', '${esc(event.riskType)}', '${esc(event.severity)}', '${esc(event.entityType)}', '${esc(event.entityKey)}', '${esc(event.metricName)}', ${observedValue === null ? 'NULL' : observedValue}, ${thresholdValue === null ? 'NULL' : thresholdValue}, '${esc(event.status || 'open')}', '${esc(event.ownerRole || 'admin')}'
WHERE NOT EXISTS (
  SELECT 1 FROM risk_event
  WHERE period_key='${esc(event.periodKey)}'
    AND risk_type='${esc(event.riskType)}'
    AND entity_key='${esc(event.entityKey)}'
    AND status IN ('open', 'acknowledged')
);`;
return [{ json: { ...event, riskInsertQuery: query } }];

const event = $json;
const recipient = event.severity === 'critical'
  ? (process.env.OPS_WA_RECIPIENT_CRITICAL || process.env.OPS_WA_RECIPIENT_HIGH || '')
  : (process.env.OPS_WA_RECIPIENT_HIGH || process.env.OPS_WA_RECIPIENT_CRITICAL || '');
const severityLabel = String(event.severity || 'warning').toUpperCase();
const summary = `[${severityLabel}] ${event.riskType} terdeteksi pada ${event.entityKey}. Observed ${event.metricName}: ${event.observedValue}. Threshold: ${event.thresholdValue}.`;
return [{
  json: {
    to: recipient,
    messageBody: summary,
    originalEvent: event
  }
}];
